cat > /tmp/extract_doc.js << 'EOF'
const html = require('fs').readFileSync('/tmp/page.html', 'utf8');
const match = html.match(/window\.__NUXT__=\(function[\s\S]*?\)\(([\s\S]*?)\);<\/script>/);
if (match) {
  // 解析函数参数
  const args = match[1].split(',').map(a => a.trim());
  console.log('Found', args.length, 'arguments');

  // 查找content字段
  const contentMatch = html.match(/content:"([^"]*)"/g);
  if (contentMatch) {
    console.log('Found content matches:', contentMatch.length);
  }
}

// 直接搜索关键信息
const titleMatch = html.match(/title:"([^"]+)"/);
const knowledgeIdMatch = html.match(/knowledgeId:"?(\d+)"?/);

console.log('Title:', titleMatch ? titleMatch[1] : 'not found');
console.log('KnowledgeId:', knowledgeIdMatch ? knowledgeIdMatch[1] : 'not found');
EOF
node /tmp/extract_doc.js 2>&1
